import pytest

def test_submit_timesheet_boundary_max_per_day_and_max_weekly(auth_session, reset_timesheet, valid_otp):
    payload = {
        "days": {"mon": 24, "tue": 24, "wed": 24, "thu": 8, "fri": 0, "sat": 0, "sun": 0},
        "otp": valid_otp
    }
    assert sum(payload["days"].values()) == 80
    resp = auth_session.post("/timesheets/submit", json=payload)
    assert resp.status_code == 200
    assert resp.json()["state"] == "submitted"

import pytest

def test_submit_timesheet_invalid_2fa_otp_blocked(auth_session, reset_timesheet):
    payload = {
        "days": {"mon": 8, "tue": 8, "wed": 8, "thu": 8, "fri": 8, "sat": 8, "sun": 8},
        "otp": "000000"
    }
    resp = auth_session.post("/timesheets/submit", json=payload)
    assert resp.status_code in (401, 403)
    state_resp = auth_session.get("/timesheets/current")
    assert state_resp.json()["state"] == "draft"
